import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"文源阁","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/yuanmingyuan/wenyuan-ge.md","filePath":"landmarks/yuanmingyuan/wenyuan-ge.md","lastUpdated":1784720050000}'),r={name:"landmarks/yuanmingyuan/wenyuan-ge.md"};function o(i,t,s,d,g,u){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="文源阁" tabindex="-1">文源阁 <a class="header-anchor" href="#文源阁" aria-label="Permalink to &quot;文源阁&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1648769170333-fd01106d8873?w=1200&amp;q=80" alt="文源阁与《四库全书》"></p><blockquote><p>一座藏书楼，半部中国文化史。七万九千卷典籍曾在此静卧，最终随一场大火散入历史的烟尘。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>文源阁位于圆明园西北部，建成于乾隆四十年（1775年），是清代为贮藏**《四库全书》**而专门建造的皇家藏书楼，与紫禁城文渊阁、沈阳文溯阁、承德文津阁并称&quot;<strong>北四阁</strong>&quot;，后又增建江南三阁，合称&quot;<strong>南北七阁</strong>&quot;。</p><p>《四库全书》是乾隆年间举全国之力编纂的<strong>中国历史上规模最大的丛书</strong>，分经、史、子、集四部，共收录古籍<strong>3503种、79337卷</strong>，抄成七部，分藏七阁。文源阁本是七部之一，专为皇帝御览而设，是圆明园作为&quot;皇家文化中心&quot;的重要象征。</p><p>1860年10月，英法联军焚掠圆明园，文源阁与阁中所藏《四库全书》同遭焚劫，部分册页被劫往海外，其余尽付一炬。如今文源阁仅存基址、碑亭与部分山石，遗址上立有御制文源阁碑，供人凭吊。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>建成年代</strong></td><td style="text-align:left;">乾隆四十年（1775年）</td></tr><tr><td style="text-align:left;"><strong>建筑形制</strong></td><td style="text-align:left;">仿宁波天一阁，外观两层、内实三层，面阔六间</td></tr><tr><td style="text-align:left;"><strong>藏书</strong></td><td style="text-align:left;">《四库全书》文源阁本（3503种、79337卷）</td></tr><tr><td style="text-align:left;"><strong>焚毁时间</strong></td><td style="text-align:left;">1860年10月（英法联军）</td></tr><tr><td style="text-align:left;"><strong>现状</strong></td><td style="text-align:left;">仅存基址、御制碑亭、玲峰石基座</td></tr><tr><td style="text-align:left;"><strong>门票</strong></td><td style="text-align:left;">含在大门10元门票内</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><h3 id="仿天一阁而建" tabindex="-1">仿天一阁而建 <a class="header-anchor" href="#仿天一阁而建" aria-label="Permalink to &quot;仿天一阁而建&quot;">​</a></h3><p>文源阁的建造遵循乾隆&quot;<strong>藏书以水克火</strong>&quot;的理念，仿浙江宁波<strong>天一阁</strong>（明代范钦所建、中国现存最古老的私家藏书楼）的形制：</p><ul><li>外观两层，内部实为三层（中层为暗层，利于防潮通风）</li><li>面阔六间，取《易经》&quot;天一生水，地六成之&quot;之意，以&quot;六&quot;数压制火患</li><li>阁前凿水池、立玲峰石（太湖石峰），阁后堆叠假山</li><li>屋面覆黑琉璃瓦，黑色属水，亦寓&quot;以水克火&quot;</li></ul><p>整座建筑环境清幽雅致，是皇家藏书楼规制的典范。</p><h3 id="四库全书的-四色书墙" tabindex="-1">四库全书的&quot;四色书墙&quot; <a class="header-anchor" href="#四库全书的-四色书墙" aria-label="Permalink to &quot;四库全书的&quot;四色书墙&quot;&quot;">​</a></h3><p>《四库全书》以<strong>四色绢面</strong>区分四部，分装于楠木函盒，按架排列于阁内三层：</p><ul><li><strong>经部</strong>：绿色绢面（儒家经典）</li><li><strong>史部</strong>：红色绢面（历代史书）</li><li><strong>子部</strong>：蓝色绢面（诸子百家）</li><li><strong>集部</strong>：灰色绢面（诗文集）</li></ul><p>七部全书共抄写近<strong>230万卷</strong>，动用数千名抄写人员，历时十余年方成——这是前工业时代世界上最浩大的文献工程之一。</p><h3 id="遗址现状" tabindex="-1">遗址现状 <a class="header-anchor" href="#遗址现状" aria-label="Permalink to &quot;遗址现状&quot;">​</a></h3><p>今日的文源阁遗址位于圆明园西北角，相对僻静。遗址上尚存：</p><ul><li><strong>文源阁碑亭</strong>与<strong>御制文源阁碑</strong>：碑身刻乾隆御制诗文，是遗址最重要的实物遗存</li><li><strong>玲峰石</strong>：原阁前的巨型太湖石峰，曾与颐和园青芝岫齐名，今残存基座</li><li><strong>阁基柱础、水池与假山遗迹</strong>：可辨识当年的格局尺度</li></ul><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="乾隆的-文化大业" tabindex="-1">乾隆的&quot;文化大业&quot; <a class="header-anchor" href="#乾隆的-文化大业" aria-label="Permalink to &quot;乾隆的&quot;文化大业&quot;&quot;">​</a></h3><p>编纂《四库全书》是乾隆自诩超越前代的文化功业。他下诏全国征书，设&quot;四库全书馆&quot;，以纪昀（纪晓岚）为总纂官，三百余位学者参与编校。</p><p>然而这场文化盛举的另一面是大规模的<strong>禁毁与删改</strong>——凡涉及反清、&quot;违碍&quot;字样的书籍或遭销毁、或遭窜改，据统计禁毁书籍达三千余种。功过并存，正是这段历史的复杂之处。</p><h3 id="七阁全书-今存三部半" tabindex="-1">七阁全书，今存三部半 <a class="header-anchor" href="#七阁全书-今存三部半" aria-label="Permalink to &quot;七阁全书，今存三部半&quot;">​</a></h3><p>1860年文源阁本被焚劫，是七部全书中<strong>第一部毁失者</strong>。此后百年间，七阁全书命运多舛：</p><table tabindex="0"><thead><tr><th style="text-align:left;">阁本</th><th style="text-align:left;">原藏地</th><th style="text-align:left;">现状</th></tr></thead><tbody><tr><td style="text-align:left;">文源阁本</td><td style="text-align:left;">圆明园</td><td style="text-align:left;"><strong>1860年被焚劫</strong>，今存残页零星</td></tr><tr><td style="text-align:left;">文渊阁本</td><td style="text-align:left;">紫禁城</td><td style="text-align:left;">现藏台北故宫博物院，保存最完整</td></tr><tr><td style="text-align:left;">文津阁本</td><td style="text-align:left;">承德避暑山庄</td><td style="text-align:left;">现藏中国国家图书馆，唯一原架原函</td></tr><tr><td style="text-align:left;">文溯阁本</td><td style="text-align:left;">沈阳故宫</td><td style="text-align:left;">现藏甘肃省图书馆（兰州）</td></tr><tr><td style="text-align:left;">文宗阁本</td><td style="text-align:left;">镇江</td><td style="text-align:left;">1853年毁于太平天国战火</td></tr><tr><td style="text-align:left;">文汇阁本</td><td style="text-align:left;">扬州</td><td style="text-align:left;">1854年毁于太平天国战火</td></tr><tr><td style="text-align:left;">文澜阁本</td><td style="text-align:left;">杭州</td><td style="text-align:left;">散佚后经晚清补抄，现藏浙江省图书馆（杭州）</td></tr></tbody></table><p>七阁之中，今仅存<strong>文渊、文津、文溯三部全本</strong>，加上补抄的文澜阁本，世称&quot;<strong>三部半</strong>&quot;。文源阁本的灰烬，是中国文献史上无法弥补的创痛。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>御制文源阁碑</strong>：遗址核心实物，乾隆御笔，碑文讲述建阁缘由</li><li><strong>阁基遗址与柱础</strong>：对照说明图辨识&quot;外观两层、内实三层&quot;的天一阁式格局</li><li><strong>玲峰石遗迹</strong>：昔日与青芝岫齐名的名石，今仅余基座，令人唏嘘</li><li><strong>《四库全书》专题展板</strong>：园内博物馆有全书编纂与流传的详细介绍</li><li><strong>僻静的凭吊氛围</strong>：游客罕至，适合静立怀想那座消失的&quot;四色书墙&quot;</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>文源阁遗址位于圆明园<strong>西北角</strong>，距南门较远，适合深度游路线，或乘观光车前往</li><li>遗址本身观览约需20-30分钟；建议配合圆明园博物馆的《四库全书》展板一并了解</li><li><strong>延伸阅读</strong>：想看《四库全书》真本，可前往中国国家图书馆（文津阁本，常设展出）或中国国家博物馆</li><li>遗址区较僻静，独自游览注意安全，冬季天黑前离开</li><li>凭吊之心为宜：这里不是一处&quot;景点&quot;，而是一座文明的坟茔</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a>——三园全貌与游览路线</li><li><a href="/beijing-travel-guide/landmarks/yuanmingyuan/xiyang-lou.html">西洋楼建筑群</a>——同年被焚的另一片废墟</li><li><a href="/beijing-travel-guide/history/yuanmingyuan-ruins.html">圆明园遗址历史专题</a>——1860年焚毁始末</li><li><a href="/beijing-travel-guide/history/national-museum.html">中国国家博物馆</a>——文津阁本相关文物可在此了解</li></ul><hr><p><strong>📍 位置</strong>：圆明园（主园）西北部 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/yuanmingyuan/">圆明园概览</a></p>',37)])])}const q=e(r,[["render",o]]);export{f as __pageData,q as default};
